"""
Generate 3 mock Excel files for batch import testing.
Run with: python generate_batch_fixtures.py
"""

import openpyxl
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from pathlib import Path

HEADERS = [
    "Company Name",
    "Stage",
    "Sector",
    "Revenue Status",
    "Current Annual Revenue",
    "Last Round Date",
    "Pre-Money Valuation",
    "Amount Raised",
    "Lead Investor",
    "Revenue at Last Round",
    "Gross Margin",
    "Runway Months",
    "Board Plan Status",
    "Customer Concentration",
    "Regulatory Risk",
    "Security Type",
    "Liquidation Preferences",
    "Option Pool %",
    "Index Movement %",
]

HEADER_FONT = Font(bold=True, size=11)
HEADER_FILL = PatternFill(start_color="E2EFDA", end_color="E2EFDA", fill_type="solid")
THIN_BORDER = Border(
    left=Side(style="thin"),
    right=Side(style="thin"),
    top=Side(style="thin"),
    bottom=Side(style="thin"),
)


def create_workbook(data: list[dict], filename: str) -> None:
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Companies"

    # Write headers
    for col_idx, header in enumerate(HEADERS, 1):
        cell = ws.cell(row=1, column=col_idx, value=header)
        cell.font = HEADER_FONT
        cell.fill = HEADER_FILL
        cell.alignment = Alignment(horizontal="center", wrap_text=True)
        cell.border = THIN_BORDER

    # Write data rows
    for row_idx, company in enumerate(data, 2):
        for col_idx, header in enumerate(HEADERS, 1):
            value = company.get(header)
            cell = ws.cell(row=row_idx, column=col_idx, value=value)
            cell.border = THIN_BORDER

    # Auto-fit column widths (approximate)
    for col_idx, header in enumerate(HEADERS, 1):
        max_len = len(header)
        for row_idx in range(2, len(data) + 2):
            val = ws.cell(row=row_idx, column=col_idx).value
            if val is not None:
                max_len = max(max_len, len(str(val)))
        ws.column_dimensions[openpyxl.utils.get_column_letter(col_idx)].width = min(max_len + 3, 30)

    output_path = Path(__file__).parent / filename
    wb.save(output_path)
    print(f"Created: {output_path}")


